import Appointment from '../models/Appointment';
import Therapist from '../models/Therapist';
import Payment from '../models/Payment';

export const createAppointmentService = async (patientId: string, data: any) => {
    const { therapistId, date, time, type, notes, amount } = data;
    const scheduledAt = new Date(`${date}T${time}:00`);

    const appointment = await Appointment.create({
        patientId,
        therapistId,
        scheduledAt,
        type: type || 'VIDEO_CALL',
        status: 'SCHEDULED',
        durationMinutes: 60,
    });

    if (amount) {
        await Payment.create({
            userId: patientId,
            appointmentId: appointment._id,
            amountUSD: amount,
            status: 'PENDING'
        });
    }

    return appointment;
};

export const getTherapistAppointmentsService = async (userId: string) => {
    const therapist = await Therapist.findOne({ userId });
    if (!therapist) throw new Error('Therapist profile not found');

    const appointments = await Appointment.find({ therapistId: therapist._id })
        .populate('patientId', 'name email avatar')
        .sort({ scheduledAt: 1 })
        .lean();

    return appointments.map(apt => ({
        ...apt,
        patient: apt.patientId
    }));
};

export const updateAppointmentStatusService = async (appointmentId: string, userId: string, data: any) => {
    const therapist = await Therapist.findOne({ userId });
    if (!therapist) throw new Error('Not authorized');

    const existingAppt = await Appointment.findOne({
        _id: appointmentId,
        therapistId: therapist._id
    });

    if (!existingAppt) throw new Error('Appointment not found');

    const updatedAppointment = await Appointment.findByIdAndUpdate(
        appointmentId,
        { status: data.status, videoRoomId: data.meetingLink },
        { new: true }
    );
    return updatedAppointment;
};

export const getPatientAppointmentsService = async (patientId: string) => {
    const appointments = await Appointment.find({ patientId })
        .populate({
            path: 'therapistId',
            populate: { path: 'userId', select: 'name avatar' }
        })
        .sort({ scheduledAt: -1 })
        .lean();

    return appointments.map(apt => {
        const therapistDoc: any = apt.therapistId;
        return {
            ...apt,
            therapist: {
                ...therapistDoc,
                user: therapistDoc?.userId
            }
        };
    });
};

import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import User from '../models/User';
import Therapist from '../models/Therapist';
import AnonymousSession from '../models/AnonymousSession';
import logger from '../utils/logger';

const JWT_EXPIRES_IN = process.env.JWT_EXPIRES_IN || '7d';
const JWT_SECRET = process.env.JWT_SECRET as string;

enum UserRole {
    PATIENT = 'PATIENT',
    THERAPIST = 'THERAPIST',
    ADMIN = 'ADMIN'
}

export const registerUser = async (data: any) => {
    const { name, email, password, role, specialization, bio, experienceYears, hourlyRate } = data;
    const normalizedRole = role && role.toUpperCase() === 'THERAPIST' ? UserRole.THERAPIST : role && role.toUpperCase() === 'ADMIN' ? UserRole.ADMIN : UserRole.PATIENT;

    const existingUser = await User.findOne({ email });
    if (existingUser) {
        throw new Error('User already exists');
    }

    const passwordHash = await bcrypt.hash(password, 10);

    const user = await User.create({
        name, email, passwordHash, role: normalizedRole, accountStatus: 'ACTIVE'
    });

    if (normalizedRole === UserRole.THERAPIST) {
        await Therapist.create({
            userId: user._id,
            licenseNumber: `TEMP_${Date.now()}`,
            licenseState: 'NA',
            licenseExpiryDate: new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
            specializations: specialization || [],
            bio: bio || '',
            experienceYears: experienceYears ? parseInt(experienceYears, 10) : 0,
            hourlyRateUSD: hourlyRate ? parseFloat(hourlyRate) : 0.0,
            hourlyRateINR: hourlyRate ? parseFloat(hourlyRate) * 83 : 0.0,
            verificationStatus: 'PENDING'
        });
    }

    const token = jwt.sign({ id: user._id, role: user.role }, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN as any });

    return {
        token,
        user: { id: user._id, name: user.name, email: user.email, role: user.role.toLowerCase() }
    };
};

export const loginUser = async (data: any) => {
    const { email, password } = data;
    const user = await User.findOne({ email });

    if (!user || !user.passwordHash) {
        throw new Error('Invalid credentials');
    }

    const isMatch = await bcrypt.compare(password, user.passwordHash);
    if (!isMatch) {
        throw new Error('Invalid credentials');
    }

    const token = jwt.sign({ id: user._id, role: user.role }, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN as any });

    return {
        token,
        user: { id: user._id, name: user.name, email: user.email, role: user.role.toLowerCase() }
    };
};

export const createAnonymousSessionService = async (data: any) => {
    const { deviceFingerprint, initialEmotion, initialMessage } = data;

    if (!deviceFingerprint || typeof deviceFingerprint !== 'string') {
        const error: any = new Error('deviceFingerprint is required and must be a string');
        error.status = 400;
        throw error;
    }
    if (deviceFingerprint.length < 10 || deviceFingerprint.length > 500) {
        const error: any = new Error('deviceFingerprint must be between 10 and 500 characters');
        error.status = 400;
        throw error;
    }

    let existingSession = await AnonymousSession.findOne({ deviceFingerprint });
    if (existingSession) {
        if (existingSession.status === 'EXPIRED') {
            const error: any = new Error('This anonymous session has expired. Please start a new session.');
            error.status = 410;
            error.codeName = 'Session Expired';
            throw error;
        }
        if (existingSession.status === 'CONVERTED_TO_USER') {
            const error: any = new Error('This device is already associated with a registered account. Please log in.');
            error.status = 409;
            error.codeName = 'Session Already Converted';
            error.userId = existingSession.convertedUserId;
            throw error;
        }

        const token = jwt.sign(
            { sessionId: existingSession._id, type: 'anonymous', deviceFingerprint: existingSession.deviceFingerprint },
            JWT_SECRET,
            { expiresIn: JWT_EXPIRES_IN as any }
        );

        return {
            status: 200,
            data: { token, sessionId: existingSession._id, messageCount: existingSession.messageCount, maxFreeMessages: existingSession.maxFreeMessages, isExisting: true }
        };
    }

    const temporaryName = `Guest_${Math.random().toString(36).substring(2, 8)}`;
    const newSession = await AnonymousSession.create({
        deviceFingerprint, temporaryName, initialMessage: initialMessage || null, detectedEmotion: initialEmotion || null, messageCount: 0, maxFreeMessages: 5, status: 'ACTIVE',
    });

    const token = jwt.sign(
        { sessionId: newSession._id, type: 'anonymous', deviceFingerprint: newSession.deviceFingerprint },
        JWT_SECRET,
        { expiresIn: JWT_EXPIRES_IN as any }
    );

    return {
        status: 201,
        data: { token, sessionId: newSession._id, temporaryName: newSession.temporaryName, messageCount: newSession.messageCount, maxFreeMessages: newSession.maxFreeMessages, isExisting: false }
    };
};

export const getSessionStatusService = async (sessionId: string) => {
    if (!sessionId) {
        const error: any = new Error('sessionId is required');
        error.status = 400;
        throw error;
    }

    const session = await AnonymousSession.findById(sessionId);
    if (!session) {
        const error: any = new Error('Session not found');
        error.status = 404;
        throw error;
    }

    return {
        sessionId: session._id,
        status: session.status,
        messageCount: session.messageCount,
        maxFreeMessages: session.maxFreeMessages,
        hasReachedLimit: session.messageCount >= session.maxFreeMessages,
        expiresAt: session.expiresAt,
        convertedUserId: session.convertedUserId
    };
};

import Chat, { IChat } from '../models/Chat';
import Conversation, { IConversation } from '../models/Conversation';
import { logger } from '../utils/logger';
import { GeminiService } from './geminiService';
import { Server as SocketIOServer } from 'socket.io';
import axios from 'axios';
import path from 'path';
import fs from 'fs';

import mongoose from 'mongoose';
import User from '../models/User';

// Load bot personality configuration
const personalityConfigPath = path.join(__dirname, '../config/bot-personality.json');
const botPersonality = fs.existsSync(personalityConfigPath)
    ? JSON.parse(fs.readFileSync(personalityConfigPath, 'utf-8'))
    : null;

// In-memory storage
const localChats: any[] = [];
const localConversations: any[] = [];

export class ChatService {
    private geminiService: GeminiService;
    private io: SocketIOServer | null = null;
    private ML_SERVICE_URL: string;

    constructor(io?: SocketIOServer) {
        this.geminiService = new GeminiService();
        this.io = io || null;
        this.ML_SERVICE_URL = process.env.ML_SERVICE_URL || 'http://localhost:5000';
    }

    async getUserConversations(userId: string): Promise<any[]> {
        if (mongoose.connection.readyState !== 1) {
            return localConversations.filter(c => c.participants.includes(userId)) as any;
        }

        const conversations = await Conversation.find({ participants: userId })
            .populate({ path: 'lastMessage', select: 'content createdAt sender type' })
            .sort({ updatedAt: -1 })
            .lean()
            .exec();

        // Populate participants using Mongoose User model
        const participantIds = Array.from(new Set(conversations.flatMap(c => c.participants)))
            .filter(id => id !== 'bot');

        const users = await User.find({ _id: { $in: participantIds } })
            .select('name role')
            .lean();

        const userMap = new Map(users.map((u: any) => [u._id.toString(), u]));

        // Combine data
        return conversations.map(c => ({
            ...c,
            participants: c.participants.map(pid => {
                if (pid === 'bot') return { _id: 'bot', name: 'AI Assistant', avatar: null };
                const u = userMap.get(pid);
                return u ? { _id: u._id, name: u.name, role: u.role } : { _id: pid, name: 'Unknown User' };
            })
        }));
    }

    async createConversation(participants: string[], type: 'direct' | 'group', groupName?: string, groupAdmin?: string): Promise<IConversation> {
        if (mongoose.connection.readyState !== 1) {
            const conv = {
                _id: 'local_conv_' + Date.now(),
                participants,
                type,
                groupName,
                groupAdmin,
                createdAt: new Date(),
                updatedAt: new Date()
            } as any;
            localConversations.push(conv);
            return conv;
        }

        // For direct chats, check if one already exists
        if (type === 'direct' && participants.length === 2) {
            const existing = await Conversation.findOne({
                participants: { $all: participants },
                type: 'direct'
            });
            if (existing) return existing;
        }

        const conversation = new Conversation({
            participants,
            type,
            groupName,
            groupAdmin
        });

        return await conversation.save();
    }

    /**
     * Analyze message for crisis indicators using ML service
     */
    private async analyzeCrisis(message: string, userId: string): Promise<any> {
        try {
            const response = await axios.post(`${this.ML_SERVICE_URL}/analyze/message`, {
                text: message,
                context: { userId }
            }, {
                timeout: 5000 // 5 second timeout
            });

            return response.data;
        } catch (error: any) {
            logger.warn('ML service unavailable, using fallback crisis detection:', error.message);
            // Fallback: Simple keyword-based detection
            return this.fallbackCrisisDetection(message);
        }
    }

    /**
     * Fallback crisis detection when ML service is down
     */
    private fallbackCrisisDetection(message: string): any {
        const lowerMessage = message.toLowerCase();
        const criticalKeywords = ['suicide', 'kill myself', 'end my life', 'want to die', 'no reason to live'];
        const highKeywords = ['hopeless', 'worthless', 'can\'t go on', 'give up', 'self-harm'];
        const moderateKeywords = ['depressed', 'anxious', 'panic', 'overwhelmed', 'scared'];

        let crisisLevel = 1;
        const detectedKeywords: string[] = [];

        for (const keyword of criticalKeywords) {
            if (lowerMessage.includes(keyword)) {
                crisisLevel = 9;
                detectedKeywords.push(keyword);
            }
        }

        if (crisisLevel < 9) {
            for (const keyword of highKeywords) {
                if (lowerMessage.includes(keyword)) {
                    crisisLevel = Math.max(crisisLevel, 7);
                    detectedKeywords.push(keyword);
                }
            }
        }

        if (crisisLevel < 7) {
            for (const keyword of moderateKeywords) {
                if (lowerMessage.includes(keyword)) {
                    crisisLevel = Math.max(crisisLevel, 4);
                    detectedKeywords.push(keyword);
                }
            }
        }

        return {
            crisis_level: crisisLevel,
            urgency: crisisLevel >= 8 ? 'critical' : crisisLevel >= 5 ? 'high' : 'low',
            keywords_detected: detectedKeywords,
            sentiment_analysis: { label: crisisLevel >= 5 ? 'negative' : 'neutral' },
            recommendations: crisisLevel >= 8 ? ['immediate_intervention'] : []
        };
    }

    async saveMessage(data: { conversationId: string; userId: string; content: string; type: string; timestamp: Date; metadata?: any }): Promise<IChat> {
        try {
            // Analyze message for crisis indicators (only for user messages, not bot)
            let crisisAnalysis = null;
            if (data.userId !== 'bot') {
                crisisAnalysis = await this.analyzeCrisis(data.content, data.userId);

                // Emit crisis event if level >= 8
                if (this.io && crisisAnalysis.crisis_level >= 8) {
                    const roomName = `user_${data.userId}`;
                    logger.info(`Emitting crisis:detected to room ${roomName} (level: ${crisisAnalysis.crisis_level})`);

                    // Emit to patient's room (for crisis modal)
                    this.io.to(roomName).emit('crisis:detected', {
                        crisisLevel: crisisAnalysis.crisis_level,
                        urgency: crisisAnalysis.urgency,
                        keywords: crisisAnalysis.keywords_detected || [],
                        sentiment: crisisAnalysis.sentiment_analysis?.label || 'unknown',
                        recommendations: crisisAnalysis.recommendations || []
                    });

                    // BROADCAST to all online therapists (the "Bat Signal")
                    logger.info(`Broadcasting therapist:crisis_alert to all therapists (level: ${crisisAnalysis.crisis_level})`);
                    this.io.emit('therapist:crisis_alert', {
                        crisisLevel: crisisAnalysis.crisis_level,
                        urgency: crisisAnalysis.urgency,
                        keywords: crisisAnalysis.keywords_detected || [],
                        sentiment: crisisAnalysis.sentiment_analysis?.label || 'unknown',
                        userId: data.userId,
                        timestamp: new Date().toISOString()
                    });
                }

                // Add crisis data to metadata
                data.metadata = {
                    ...data.metadata,
                    crisisLevel: crisisAnalysis.crisis_level,
                    crisisAnalysis
                };
            }

            if (mongoose.connection.readyState !== 1) {
                const chat = {
                    _id: 'local_msg_' + Date.now(),
                    conversationId: data.conversationId,
                    sender: data.userId === 'bot' ? 'bot' : data.userId,
                    content: data.content,
                    type: data.type,
                    metadata: data.metadata,
                    createdAt: new Date(),
                    updatedAt: new Date()
                } as any;
                localChats.push(chat);

                // Update local conversation
                const convIndex = localConversations.findIndex(c => c._id === data.conversationId);
                if (convIndex !== -1) {
                    localConversations[convIndex].lastMessage = chat;
                    localConversations[convIndex].updatedAt = new Date();
                }

                if (this.io && data.conversationId) {
                    this.io.to(data.conversationId).emit('chat:message', chat);
                }

                return chat;
            }

            const chat = new Chat({
                conversationId: data.conversationId,
                sender: data.userId === 'bot' ? 'bot' : data.userId,
                content: data.content,
                type: data.type,
                metadata: data.metadata
            });

            await chat.save();

            // Update conversation last message
            await Conversation.findByIdAndUpdate(data.conversationId, {
                lastMessage: chat._id,
                updatedAt: new Date()
            });

            if (this.io && data.conversationId) {
                this.io.to(data.conversationId).emit('chat:message', chat);
            }

            return chat;
        } catch (error) {
            logger.error('Error saving message:', error);
            throw error;
        }
    }

    async getRecentMessages(conversationId: string, limit: number): Promise<any[]> {
        if (mongoose.connection.readyState !== 1) {
            return localChats
                .filter(c => c.conversationId === conversationId)
                .sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime())
                .slice(0, limit);
        }

        const messages = await Chat.find({ conversationId })
            .sort({ createdAt: -1 })
            .limit(limit)
            .lean()
            .exec();

        // Populate sender details using Mongoose User Model
        const senderIds = Array.from(new Set(messages.map((m: any) => m.sender).filter(s => s && s !== 'bot')));
        const users = await User.find({ _id: { $in: senderIds } })
            .select('name')
            .lean();

        const userMap = new Map(users.map((u: any) => [u._id.toString(), u]));

        return messages.map((m: any) => {
            let senderDetails = null;
            if (m.sender === 'bot') {
                senderDetails = { _id: 'bot', name: 'Mindora (AI)' };
            } else if (m.sender) {
                const u = userMap.get(m.sender.toString());
                senderDetails = u ? { _id: u._id, name: u.name } : { _id: m.sender, name: 'Unknown' };
            }

            return {
                ...m,
                sender: senderDetails
            };
        });
    }

    async generateBotResponse(message: string, analysis: any, conversationId: string): Promise<any> {
        console.log('[DEBUG] generateBotResponse called');
        try {
            const crisisLevel = analysis.crisis_level || 1;
            const sentiment = analysis.sentiment_analysis?.label || 'neutral';
            const keywords = analysis.keywords_detected || [];

            // For critical crisis (>= 8), use brief response since modal will appear
            if (crisisLevel >= 8) {
                return {
                    content: "I see you're going through a very difficult time. Please look at the screen—there's immediate help available for you. You're not alone.",
                    type: 'bot_response',
                    suggestions: ['I need help now']
                };
            }

            // Retrieve recent context to pass to the LLM
            let history = "";
            try {
                const recentMessages = await this.getRecentMessages(conversationId, 5);
                history = recentMessages.reverse().map(m => {
                    const sender = m.sender ? 'User' : 'Assistant';
                    return `${sender}: ${m.content}`;
                }).join('\n');
            } catch (err) {
                console.warn('Could not fetch history, continuing without it', err);
            }

            // Build system prompt from bot-personality.json if available
            let systemPrompt = botPersonality?.system_prompt?.base || '';

            // Use response template based on crisis level
            let guidanceNote = '';
            if (botPersonality?.system_prompt?.response_templates) {
                const templates = botPersonality.system_prompt.response_templates;
                if (crisisLevel >= 7 && templates.crisis_level_7_8) {
                    guidanceNote = `\nExample tone: "${templates.crisis_level_7_8.example}"`;
                } else if (crisisLevel >= 4 && templates.crisis_level_4_6) {
                    guidanceNote = `\nExample tone: "${templates.crisis_level_4_6.example}"`;
                } else if (templates.crisis_level_1_3) {
                    guidanceNote = `\nExample tone: "${templates.crisis_level_1_3.example}"`;
                }
            }

            const prompt = `${systemPrompt}

ANALYSIS CONTEXT:
- Crisis Level: ${crisisLevel}/10
- Sentiment: ${sentiment}
- Detected Keywords: ${keywords.join(', ')}
${guidanceNote}

CONVERSATION HISTORY:
${history}

CURRENT USER MESSAGE:
"${message}"

Respond with empathy and care:
`;

            const responseContent = await this.geminiService.generateResponse(prompt);
            console.log('[DEBUG] Gemini response received');

            let suggestions = ['Tell me more', 'I am listening', 'Thank you'];
            if (crisisLevel >= 5) {
                suggestions = ['I need support', 'Talk to therapist', 'Crisis resources'];
            } else if (sentiment === 'negative') {
                suggestions = ['I feel overwhelmed', 'It is hard', 'I need a distraction'];
            } else if (sentiment === 'positive') {
                suggestions = ['I am proud of myself', 'Things are looking up', 'Thanks for asking'];
            }

            return {
                content: responseContent.trim(),
                type: 'bot_response',
                suggestions: suggestions
            };

        } catch (error) {
            logger.error('Failed to generate response from Gemini, falling back to static logic:', error);
            return this.getFallbackResponse(message, analysis);
        }
    }

    private getFallbackResponse(message: string, analysis: any): any {
        const crisisLevel = analysis.crisis_level || 1;
        const sentiment = analysis.sentiment_analysis?.label || 'neutral';

        if (crisisLevel >= 7) {
            return {
                content: "I'm detecting that you're going through a very difficult moment. I want to ensure you're safe. Please reach out to the Suicide & Crisis Lifeline by calling 988. I am just a bot, but your life matters.",
                type: 'bot_response',
                suggestions: ['Call 988', 'Emergency Resources']
            };
        }

        if (sentiment === 'negative') {
            return {
                content: "I'm sorry you're feeling this way. I'm here to listen. Can you tell me more about what's going on?",
                type: 'bot_response',
                suggestions: ['I am sad', 'I am stressed']
            };
        }

        return {
            content: "I'm listening. Please go on.",
            type: 'bot_response',
            suggestions: ['Tell me more', 'Just venting']
        };
    }

    async processVoiceMessage(data: any): Promise<any> {
        // Placeholder for voice processing (STT)
        // In the future, we could use Gemini 1.5 Pro's audio capabilities too!
        return {
            transcription: "Voice message processing not yet implemented.",
            sentiment: "neutral"
        };
    }
}

import axios from 'axios';
import { logger } from '../utils/logger';
import CrisisEvent from '../models/CrisisEvent';
export class CrisisDetectionService {
    private mlServiceUrl: string;

    constructor() {
        this.mlServiceUrl = process.env.ML_SERVICE_URL || 'http://127.0.0.1:8000';
    }

    async analyzeMessage(message: string, context: any): Promise<any> {
        const lowerMsg = message.toLowerCase();

        // 1. Enhanced Regex Crisis Detection (Handles typos & variations)
        const crisisPatterns = [
            /suicid/i,
            /(kill|end|hurt).*(myself|me|life)/i,
            /(want|wish).*(die|dead)/i,
            /(no reason|nothing).*live/i,
            /self[\s-]?harm/i,
            /cutting/i,
            /overdose/i
        ];

        const isCrisis = crisisPatterns.some(pattern => pattern.test(lowerMsg));

        if (isCrisis) {
            logger.warn(`CRITICAL: Local Regex detection triggered for message: "${message}"`);
            return {
                crisis_level: 9, // Immediate High Crisis
                urgency: 'critical',
                requires_immediate_escalation: true,
                sentiment_analysis: { label: 'negative', score: 0.95 },
                keywords_detected: ['local_crypto_crisis_match'],
                recommendations: ['Immediate professional intervention', 'Safety plan']
            };
        }

        // 2. Basic Local Sentiment Analysis (Fallback)
        // Simple dictionary-based approach
        const negativeWords = ['sad', 'depressed', 'anxious', 'scared', 'hurt', 'pain', 'bad', 'terrible', 'awful', 'cry', 'crying', 'lonely', 'tired', 'hate', 'fear'];
        const positiveWords = ['happy', 'good', 'great', 'better', 'love', 'excited', 'wonderful', 'thanks', 'thank', 'hope', 'joy'];

        let sentimentScore = 0;
        const words = lowerMsg.split(/\s+/);
        words.forEach(w => {
            if (negativeWords.includes(w)) sentimentScore--;
            if (positiveWords.includes(w)) sentimentScore++;
        });

        const localSentiment = sentimentScore > 0 ? 'positive' : (sentimentScore < 0 ? 'negative' : 'neutral');

        try {
            const response = await axios.post(`${this.mlServiceUrl}/analyze/message`, {
                text: message,
                user_id: context.userId,
                context: {
                    conversation_id: context.conversationId,
                    history: context.messageHistory
                }
            });
            return response.data;
        } catch (error) {
            // logger.error('Crisis detection service error:', error); // Silence error to avoid spam if ML check is just a bonus
            // Fallback response
            return {
                crisis_level: (sentimentScore < -2) ? 4 : 1, // Elevate crisis slightly if very negative
                urgency: 'low',
                requires_immediate_escalation: false,
                sentiment_analysis: { label: localSentiment, score: 0.5 + (sentimentScore * 0.1) },
                keywords_detected: [],
                recommendations: []
            };
        }
    }

    async createEscalation(data: any): Promise<any> {
        try {
            logger.warn(`Creating persistent escalation for user ${data.userId} in conversation ${data.conversationId}`);

            const event = await CrisisEvent.create({
                userId: data.userId,
                conversationId: data.conversationId,
                crisisLevel: data.crisis_level || 5,
                sentimentScore: data.sentiment_analysis?.score || 0,
                keywordsDetected: data.keywords_detected || [],
                urgency: data.urgency || 'medium',
                requiresEscalation: data.requires_immediate_escalation || false,
                status: 'PENDING',
                actionTaken: 'system_detected'
            });

            return event;
        } catch (error) {
            logger.error('Failed to persist crisis event:', error);
            // Fallback for demo/failure safety - return a mock but log the error strictly
            return {
                id: `esc_fallback_${Date.now()}`,
                ...data,
                createdAt: new Date(),
                status: 'pending',
                _error: 'persistence_failed'
            };
        }
    }
}

