                                            >
                                                {suggestion}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <form onSubmit={handleSendMessage} className="p-4 border-t border-slate-200 flex space-x-2">
                <button type="button" className="p-2 hover:bg-slate-100 rounded-full text-slate-500">
                    <Mic className="h-5 w-5" />
                </button>
                <input
                    type="text"
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    placeholder="Type a message..."
                    className="flex-1 px-4 py-2 border border-slate-300 rounded-full focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
                />
                <button
                    type="submit"
                    disabled={!newMessage.trim()}
                    className="p-2 bg-primary-600 text-white rounded-full hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                    <Send className="h-5 w-5" />
                </button>
            </form>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { MessageCircle, X, Send, Minimize2, Maximize2, Bot } from 'lucide-react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

interface Message {
    _id: string;
    content: string;
    sender: { _id: string; name: string };
    createdAt: string;
}

export const FloatingChatWidget: React.FC = () => {
    const { user } = useAuth();
    const [isOpen, setIsOpen] = useState(false);
    const [isExpanded, setIsExpanded] = useState(false);
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [conversationId, setConversationId] = useState<string | null>(null);
    const [isTyping, setIsTyping] = useState(false);

    // Auto-scroll ref
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isTyping, isOpen]);

    useEffect(() => {
        if (isOpen && !conversationId) {
            initializeBotChat();
        }
    }, [isOpen]);

    const initializeBotChat = async () => {
        try {
            // Check for existing bot conversation or create one
            const response = await api.post('/chat/conversations', {
                participants: ['bot'],
                type: 'direct'
            });
            setConversationId(response.data._id);
            // Fetch recent messages
            if (response.data._id) {
                const msgResponse = await api.get(`/chat/conversations/${response.data._id}/messages`);
                // Backend returns Newest First, we want Oldest First (Chronological)
                setMessages(msgResponse.data.reverse());
            }
        } catch (error) {
            console.error('Failed to init bot chat', error);
        }
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMessage.trim() || !conversationId) return;

        try {
            const content = newMessage;
            setNewMessage('');

            // Optimistic update
            const tempMsg: Message = {
                _id: Date.now().toString(),
                content,
                sender: { _id: (user as any)?._id || 'me', name: user?.name || 'Me' },
                createdAt: new Date().toISOString()
            };
            setMessages(prev => [...prev, tempMsg]);
            setIsTyping(true); // Start typing indicator

            await api.post(`/chat/conversations/${conversationId}/messages`, { content });

            // Poll for bot response (attempt every 2s for 30s)
            let attempts = 0;
            const maxAttempts = 15;

            const pollInterval = setInterval(async () => {
                attempts++;
                try {
                    const msgResponse = await api.get(`/chat/conversations/${conversationId}/messages`);
                    // Reverse to get Chronological order
                    const newMessages = msgResponse.data.reverse();

                    // Check if there's a new message from the bot
                    // Last message in chronological list should be the newest
                    const lastMsg = newMessages[newMessages.length - 1];

                    // Safe check for sender (bot has no sender or sender is null)
                    const isBot = !lastMsg.sender || lastMsg.sender === null;
                    const isOtherUser = lastMsg.sender?._id !== (user as any)?._id && lastMsg.sender?._id !== 'me';

                    if (lastMsg && (isBot || isOtherUser)) {
                        setMessages(newMessages);
                        setIsTyping(false); // Stop typing indicator
                        clearInterval(pollInterval);
                    } else if (attempts >= maxAttempts) {
                        setIsTyping(false); // Stop typing indicator on timeout
                        clearInterval(pollInterval);
                    }
                } catch (err) {
                    console.error('Polling error', err);
                }
            }, 2000);

        } catch (error) {
            console.error('Failed to send message', error);
        }
    };

    if (!isOpen) {
        return (
            <button
                onClick={() => setIsOpen(true)}
                className="fixed bottom-6 right-6 w-14 h-14 bg-indigo-600 text-white rounded-full shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center z-50 hover:scale-110"
            >
                <MessageCircle className="w-8 h-8" />
            </button>
        );
    }

    return (
        <div className={`fixed bottom-6 right-6 bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col z-50 transition-all duration-300 ${isExpanded ? 'w-96 h-[600px]' : 'w-80 h-[500px]'}`}>
            {/* Header */}
            <div className="p-4 bg-indigo-600 text-white rounded-t-2xl flex justify-between items-center shadow-md">
                <div className="flex items-center gap-2">
                    <div className="relative">
                        <Bot className="w-6 h-6" />
                        <div className="absolute -bottom-1 -right-1 w-2.5 h-2.5 bg-green-400 rounded-full border-2 border-indigo-600 animate-pulse" />
                    </div>
                    <span className="font-bold">Mindora</span>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setIsExpanded(!isExpanded)} className="p-1 hover:bg-indigo-500 rounded transition-colors">
                        {isExpanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
                    </button>
                    <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-indigo-500 rounded transition-colors">
                        <X className="w-5 h-5" />
                    </button>
                </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 scrollbar-thin scrollbar-thumb-slate-200">
                {messages.map((msg) => {
                    const isMe = msg.sender?._id === (user as any)?._id || msg.sender?._id === 'me';
                    return (
                        <div key={msg._id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                            {!isMe && (
                                <div className="w-8 h-8 rounded-full bg-green-100 flex items-center justify-center mr-2 self-end mb-1">
                                    <Bot className="w-5 h-5 text-green-600" />
                                </div>
                            )}
                            <div className={`max-w-[75%] p-3.5 rounded-2xl text-sm shadow-sm leading-relaxed ${isMe
                                ? 'bg-blue-500 text-white rounded-tr-none'
                                : 'bg-green-100 text-green-900 rounded-tl-none'
                                }`}>
                                {msg.content}
                            </div>
                        </div>
                    );
                })}
                {isTyping && (
                    <div className="flex justify-start items-end">
                        <div className="w-8 h-8 rounded-full bg-green-100 flex items-center justify-center mr-2 mb-1">
                            <Bot className="w-5 h-5 text-green-600" />
                        </div>
                        <div className="bg-green-100 text-green-900 border border-green-200 p-4 rounded-2xl rounded-tl-none shadow-sm flex items-center space-x-1.5 h-12">
                            <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                            <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                            <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                        </div>
                    </div>
                )}
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-center p-6 text-slate-500 space-y-3 opacity-60">
                        <Bot className="w-12 h-12 text-slate-300" />
                        <p className="text-sm">Hi! I'm Mindora. I'm here to listen and support you. How are you feeling today?</p>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleSendMessage} className="p-3 border-t border-slate-100 bg-white rounded-b-2xl">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        placeholder="Type a message..."
                        className="flex-1 px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all placeholder:text-slate-400"
                    />
                    <button
                        type="submit"
                        disabled={!newMessage.trim()}
                        className="p-2.5 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all transform hover:scale-105 active:scale-95 shadow-sm"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </div>
            </form>
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import type { User, AuthState } from '../types';

interface AuthContextType extends AuthState {
    login: (token: string, user: User) => void;
    logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [state, setState] = useState<AuthState>({
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: true,
    });

    useEffect(() => {
        const token = localStorage.getItem('token');
        const userStr = localStorage.getItem('user');

        if (token && userStr) {
            try {
                const user = JSON.parse(userStr);
                setState({
                    user,
                    token,
                    isAuthenticated: true,
                    isLoading: false,
                });
            } catch (e) {
                localStorage.removeItem('token');
                localStorage.removeItem('user');
                setState(prev => ({ ...prev, isLoading: false }));
            }
        } else {
            setState(prev => ({ ...prev, isLoading: false }));
        }
    }, []);

    const login = (token: string, user: User) => {
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        setState({
            user,
            token,
            isAuthenticated: true,
            isLoading: false,
        });
    };

    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setState({
            user: null,
            token: null,
            isAuthenticated: false,
            isLoading: false,
        });
    };

    return (
        <AuthContext.Provider value={{ ...state, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import React, { createContext, useContext, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { X, CheckCircle, AlertCircle, Info, AlertTriangle } from 'lucide-react';

export type ToastType = 'success' | 'error' | 'info' | 'warning';

export interface Toast {
    id: string;
    message: string;
    type: ToastType;
}

interface ToastContextType {
    showToast: (message: string, type: ToastType) => void;
    removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within a ToastProvider');
    }
    return context;
};

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const showToast = useCallback((message: string, type: ToastType) => {
        const id = Math.random().toString(36).substring(2, 9);
        setToasts((prev) => [...prev, { id, message, type }]);

        // Auto remove after 5 seconds
        setTimeout(() => {
            removeToast(id);
        }, 5000);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts((prev) => prev.filter((toast) => toast.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ showToast, removeToast }}>
            {children}
            <div className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 pointer-events-none">
                <AnimatePresence>
                    {toasts.map((toast) => (
                        <ToastItem key={toast.id} toast={toast} onClose={() => removeToast(toast.id)} />
                    ))}
                </AnimatePresence>
            </div>
        </ToastContext.Provider>
    );
};

const ToastItem: React.FC<{ toast: Toast; onClose: () => void }> = ({ toast, onClose }) => {
    const icons = {
        success: <CheckCircle className="w-5 h-5 text-green-500" />,
        error: <AlertCircle className="w-5 h-5 text-red-500" />,
        warning: <AlertTriangle className="w-5 h-5 text-yellow-500" />,
        info: <Info className="w-5 h-5 text-blue-500" />
    };

    const bgColors = {
        success: 'bg-green-50 border-green-200',
        error: 'bg-red-50 border-red-200',
        warning: 'bg-yellow-50 border-yellow-200',
        info: 'bg-blue-50 border-blue-200'
    };

    return (
        <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.3 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.5, transition: { duration: 0.2 } }}
            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-lg shadow-lg border ${bgColors[toast.type]} min-w-[300px] max-w-sm backdrop-blur-sm`}
        >
            {icons[toast.type]}
            <p className="flex-1 text-sm font-medium text-gray-800">{toast.message}</p>
            <button
                onClick={onClose}
                className="p-1 rounded-full hover:bg-black/5 transition-colors"
            >
                <X className="w-4 h-4 text-gray-500" />
            </button>
        </motion.div>
    );
};

import { useState, useEffect } from 'react';
import { io, Socket } from 'socket.io-client';

interface CrisisDetection {
    crisisLevel: number;
    urgency: string;
    keywords: string[];
    sentiment: string;
    recommendations: string[];
}

interface UseCrisisDetectionReturn {
    crisisLevel: number;
    isCritical: boolean;
    showModal: boolean;
    detectedKeywords: string[];
    dismissModal: () => void;
}

const CRISIS_THRESHOLD = 8; // Show modal for crisis level >= 8
const SOCKET_URL = import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:3001';

export const useCrisisDetection = (): UseCrisisDetectionReturn => {
    const [crisisLevel, setCrisisLevel] = useState<number>(0);
    const [detectedKeywords, setDetectedKeywords] = useState<string[]>([]);
    const [showModal, setShowModal] = useState<boolean>(false);
    const [_, setSocket] = useState<Socket | null>(null);

    useEffect(() => {
        // Initialize Socket.IO connection
        const newSocket = io(SOCKET_URL, {
            transports: ['websocket', 'polling'],
            auth: {
                token: localStorage.getItem('anonymousSessionToken') || localStorage.getItem('token'),
            },
        });

        // Listen for crisis detection events from backend
        newSocket.on('crisis:detected', (data: CrisisDetection) => {
            console.log('Crisis detected:', data);
            setCrisisLevel(data.crisisLevel);
            setDetectedKeywords(data.keywords || []);

            // Auto-show modal for critical levels
            if (data.crisisLevel >= CRISIS_THRESHOLD) {
                setShowModal(true);
            }
        });

        // Connection error handling
        newSocket.on('connect_error', (error) => {
            console.error('Socket connection error:', error);
        });

        setSocket(newSocket);

        // Cleanup on unmount
        return () => {
            newSocket.close();
        };
    }, []);

    const dismissModal = () => {
        // Only allow dismissal for non-critical levels (< 9)
        if (crisisLevel < 9) {
            setShowModal(false);
        }
    };

    return {
        crisisLevel,
        isCritical: crisisLevel >= CRISIS_THRESHOLD,
        showModal,
        detectedKeywords,
        dismissModal,
    };
};

import { useState, useEffect } from 'react';
import { io, Socket } from 'socket.io-client';

export interface CrisisAlert {
    id: string;
    crisisLevel: number;
    urgency: string;
    keywords: string[];
    message: string; // Alert message to display
    patientInfo: string;
    timestamp: Date;
    userId: string;
}

interface UseTherapistCrisisAlertsReturn {
    crisisAlerts: CrisisAlert[];
    acceptCrisisSession: (alertId: string) => void;
    dismissAlert: (alertId: string) => void;
}

const SOCKET_URL = import.meta.env.VITE_API_URL?.replace('/api', '') || 'http://localhost:3001';

export const useTherapistCrisisAlerts = (): UseTherapistCrisisAlertsReturn => {
    const [crisisAlerts, setCrisisAlerts] = useState<CrisisAlert[]>([]);
    const [socket, setSocket] = useState<Socket | null>(null);

    useEffect(() => {
        // Initialize Socket.IO connection for therapists
        const newSocket = io(SOCKET_URL, {
            transports: ['websocket', 'polling'],
            auth: {
                token: localStorage.getItem('token'), // Therapist JWT token
                role: 'therapist'
            },
        });

        // Listen for crisis alerts broadcast to all therapists
        newSocket.on('therapist:crisis_alert', (data: any) => {
            console.log('Therapist received crisis alert:', data);

            const newAlert: CrisisAlert = {
                id: `alert_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                crisisLevel: data.crisisLevel,
                urgency: data.urgency,
                keywords: data.keywords || [],
                message: data.message || `Level ${data.crisisLevel}/10 emergency - Immediate assistance required`,
                patientInfo: `Anonymous Patient (Level ${data.crisisLevel}/10 emergency)`,
                timestamp: new Date(),
                userId: data.userId || 'unknown'
            };

            setCrisisAlerts(prev => [newAlert, ...prev]);

            // Play alert sound (optional)
            try {
                const audio = new Audio('/alert-sound.mp3');
                audio.play().catch(e => console.log('Audio play failed:', e));
            } catch (e) {
                console.log('Audio not available');
            }

            // Browser notification (if permission granted)
            if ('Notification' in window && Notification.permission === 'granted') {
                new Notification('🚨 Emergency Session Request', {
                    body: `Crisis Level ${data.crisisLevel}/10 - Patient needs immediate support`,
                    icon: '/crisis-icon.png',
                    tag: newAlert.id
                });
            }
        });

        // Connection status
        newSocket.on('connect', () => {
            console.log('Therapist connected to crisis alert system');
        });

        newSocket.on('connect_error', (error) => {
            console.error('Therapist socket connection error:', error);
        });

        setSocket(newSocket);

        // Request notification permission on mount
        if ('Notification' in window && Notification.permission === 'default') {
            Notification.requestPermission();
        }

        // Cleanup on unmount
        return () => {
            newSocket.close();
        };
    }, []);

    const acceptCrisisSession = (alertId: string) => {
        // Remove alert from list
        setCrisisAlerts(prev => prev.filter(alert => alert.id !== alertId));

        // Notify backend that this therapist accepted the session
        if (socket) {
            const alert = crisisAlerts.find(a => a.id === alertId);
            if (alert) {
                socket.emit('therapist:accept_crisis', {
                    alertId,
                    userId: alert.userId,
                    therapistId: 'current_therapist_id' // TODO: Get from auth context
                });
            }
        }

        console.log(`Therapist accepted crisis session: ${alertId}`);
    };

    const dismissAlert = (alertId: string) => {
        // Remove alert - another therapist will handle it
        setCrisisAlerts(prev => prev.filter(alert => alert.id !== alertId));
        console.log(`Alert dismissed: ${alertId}`);
    };

    return {
        crisisAlerts,
        acceptCrisisSession,
        dismissAlert
    };
};

