                                        ? 'bg-primary-600 text-white hover:bg-primary-700 hover:-translate-y-0.5 shadow-primary-500/25'
                                        : 'bg-slate-100 text-slate-300 cursor-not-allowed border border-slate-200'
                                        }`}
                                >
                                    <Send className="w-5 h-5 ml-0.5" />
                                </button>
                            </div>
